"use client";

import { useState } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { signInWithEmailAndPassword, signInWithRedirect, signInWithPopup, GoogleAuthProvider } from "firebase/auth";
import { auth } from "@/lib/firebase";
import { routes } from "@/lib/routes";
import { useAuth } from "@/components/providers/AuthProvider";
import { useEffect } from "react";
import { Navbar } from "@/components/layout/Navbar";
import { Footer } from "@/components/layout/Footer";

export default function LoginPage() {
  const router = useRouter();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const { user } = useAuth();

  useEffect(() => {
    if (user) {
      router.push(routes.account);
    }
  }, [user, router]);

  const handleEmailLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setLoading(true);

    try {
      const userCredential = await signInWithEmailAndPassword(auth, email, password);

      if (!userCredential.user.emailVerified) {
        await auth.signOut();
        setError("Hesabınıza giriş yapabilmek için lütfen e-posta adresinize gönderilen doğrulama bağlantısına tıklayın.");
        setLoading(false);
        return;
      }

      router.push(routes.account);
    } catch (err: any) {
      setError("Giriş başarısız. Lütfen bilgilerinizi kontrol edin.");
    } finally {
      setLoading(false);
    }
  };

  const handleGoogleLogin = async () => {
    setError("");
    const provider = new GoogleAuthProvider();
    try {
      // Use popup for better stability
      await signInWithPopup(auth, provider);
    } catch (err: any) {
      if (err.code === "auth/popup-blocked") {
        // Fallback to redirect if popup is blocked
        await signInWithRedirect(auth, provider);
      } else {
        console.error(err);
        setError(`Google ile giriş başarısız: ${err.message}`);
      }
    }
  };

  return (
    <div className="w-full min-h-screen bg-black flex flex-col pt-24 pb-20">
      <div className="container max-w-screen-xl mx-auto px-4 flex-1 flex items-center justify-center">
        <div className="w-full max-w-md bg-white/5 border border-white/10 p-6 sm:p-12 box-border">
          <h1 className="text-2xl sm:text-3xl font-light uppercase tracking-widest text-white text-center mb-8">
            GİRİŞ YAP
          </h1>

          {error && (
            <div className="bg-red-500/10 border border-red-500/50 text-red-500 text-sm p-3 mb-6 text-center">
              {error}
            </div>
          )}

          <form onSubmit={handleEmailLogin} className="space-y-5">
            <div>
              <label className="block text-xs uppercase tracking-widest text-white/50 mb-2">
                E-POSTA ADRESİ
              </label>
              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                required
                className="w-full bg-transparent border border-white/20 text-white px-4 py-3 focus:outline-none focus:border-white transition-colors"
                placeholder="ornek@email.com"
              />
            </div>
            <div>
              <label className="block text-xs uppercase tracking-widest text-white/50 mb-2">
                ŞİFRE
              </label>
              <input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                required
                className="w-full bg-transparent border border-white/20 text-white px-4 py-3 focus:outline-none focus:border-white transition-colors"
                placeholder="••••••••"
              />
            </div>

            <button
              type="submit"
              disabled={loading}
              className="w-full bg-white text-black font-medium py-4 uppercase tracking-widest text-sm hover:bg-white/90 transition-colors disabled:opacity-50"
            >
              {loading ? "GİRİŞ YAPILIYOR..." : "GİRİŞ YAP"}
            </button>
          </form>

          <div className="relative my-8">
            <div className="absolute inset-0 flex items-center">
              <div className="w-full border-t border-white/10"></div>
            </div>
            <div className="relative flex justify-center text-xs uppercase tracking-widest">
              <span className="bg-[#0D0D0D] px-4 text-white/50">VEYA</span>
            </div>
          </div>

          <button
            onClick={handleGoogleLogin}
            type="button"
            className="w-full bg-transparent border border-white text-white font-medium py-3 uppercase tracking-widest text-sm hover:bg-white/10 transition-colors flex items-center justify-center gap-3"
          >
            <svg viewBox="0 0 24 24" className="w-5 h-5 fill-current">
              <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" />
              <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" />
              <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" />
              <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" />
            </svg>
            Google İLE GİRİŞ YAP
          </button>

          <div className="mt-8 text-center text-sm text-white/50">
            Hesabınız yok mu?{" "}
            <Link href={routes.register} className="text-white hover:underline transition-all">
              KAYIT OL
            </Link>
          </div>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { createUserWithEmailAndPassword, signInWithRedirect, signInWithPopup, GoogleAuthProvider, updateProfile, sendEmailVerification } from "firebase/auth";
import { auth, db } from "@/lib/firebase";
import { doc, setDoc, serverTimestamp } from "firebase/firestore";
import { useAuth } from "@/components/providers/AuthProvider";
import { routes } from "@/lib/routes";
import { useEffect } from "react";

export default function RegisterPage() {
  const router = useRouter();
  const [firstName, setFirstName] = useState("");
  const [lastName, setLastName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const { user } = useAuth();

  useEffect(() => {
    if (user && !isSuccess && !loading) {
      router.push(routes.account);
    }
  }, [user, router, isSuccess, loading]);

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setLoading(true);

    try {
      // Create user
      const userCredential = await createUserWithEmailAndPassword(auth, email, password);
      const user = userCredential.user;

      // Update auth profile
      await updateProfile(user, {
        displayName: `${firstName} ${lastName}`,
      });

      // Create base user document in Firestore
      await setDoc(doc(db, "users", user.uid), {
        firstName,
        lastName,
        email,
        createdAt: serverTimestamp(),
      });

      // Send email verification
      await sendEmailVerification(user);

      // Sign out to enforce login after verification
      await auth.signOut();

      setIsSuccess(true);
    } catch (err: any) {
      if (err.code === "auth/email-already-in-use") {
        setError("Bu e-posta adresi zaten kullanımda.");
      } else {
        setError("Kayıt işlemi başarısız oldu. Lütfen tekrar deneyin.");
      }
    } finally {
      setLoading(false);
    }
  };

  const handleGoogleLogin = async () => {
    setError("");
    const provider = new GoogleAuthProvider();
    try {
      // Use popup for better UX and stability on desktop
      await signInWithPopup(auth, provider);
    } catch (err: any) {
      if (err.code === "auth/popup-blocked") {
        // Fallback to redirect if popup is blocked
        await signInWithRedirect(auth, provider);
      } else {
        console.error(err);
        setError(`Google ile kayıt başarısız: ${err.message}`);
      }
    }
  };

  if (isSuccess) {
    return (
      <div className="w-full min-h-screen bg-black flex flex-col pt-24 pb-20">
        <div className="container max-w-screen-xl mx-auto px-4 flex-1 flex items-center justify-center">
          <div className="w-full max-w-md bg-white/5 border border-white/10 p-6 sm:p-12 box-border text-center">
            <h1 className="text-2xl sm:text-3xl font-light uppercase tracking-widest text-white mb-6">
              KAYIT BAŞARILI
            </h1>
            <p className="text-white/75 text-sm leading-relaxed mb-8">
              E-posta adresinize bir doğrulama bağlantısı gönderdik. Lütfen gelen kutunuzu (ve spam klasörünü) kontrol edin ve hesabınızı doğrulamak için bağlantıya tıklayın.
            </p>
            <Link
              href={routes.login}
              className="inline-block bg-white text-black font-medium px-8 py-4 uppercase tracking-widest text-sm hover:bg-white/90 transition-colors"
            >
              GİRİŞ YAP
            </Link>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="w-full min-h-screen bg-black flex flex-col pt-24 pb-20">
      <div className="container max-w-screen-xl mx-auto px-4 flex-1 flex items-center justify-center">
        <div className="w-full max-w-md bg-white/5 border border-white/10 p-6 sm:p-12 box-border">
          <h1 className="text-2xl sm:text-3xl font-light uppercase tracking-widest text-white text-center mb-8">
            HESAP OLUŞTUR
          </h1>

          {error && (
            <div className="bg-red-500/10 border border-red-500/50 text-red-500 text-sm p-3 mb-6 text-center">
              {error}
            </div>
          )}

          <form onSubmit={handleRegister} className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-[10px] sm:text-xs uppercase tracking-widest text-white/50 mb-2">
                  AD
                </label>
                <input
                  type="text"
                  value={firstName}
                  onChange={(e) => setFirstName(e.target.value)}
                  required
                  className="w-full bg-transparent border border-white/20 text-white px-4 py-3 focus:outline-none focus:border-white transition-colors text-sm"
                  placeholder="Seçkin"
                />
              </div>
              <div>
                <label className="block text-[10px] sm:text-xs uppercase tracking-widest text-white/50 mb-2">
                  SOYAD
                </label>
                <input
                  type="text"
                  value={lastName}
                  onChange={(e) => setLastName(e.target.value)}
                  required
                  className="w-full bg-transparent border border-white/20 text-white px-4 py-3 focus:outline-none focus:border-white transition-colors text-sm"
                  placeholder="Yılmaz"
                />
              </div>
            </div>

            <div>
              <label className="block text-[10px] sm:text-xs uppercase tracking-widest text-white/50 mb-2 mt-2">
                E-POSTA ADRESİ
              </label>
              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                required
                className="w-full bg-transparent border border-white/20 text-white px-4 py-3 focus:outline-none focus:border-white transition-colors text-sm"
                placeholder="ornek@email.com"
              />
            </div>

            <div>
              <label className="block text-[10px] sm:text-xs uppercase tracking-widest text-white/50 mb-2 mt-2">
                ŞİFRE
              </label>
              <input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                required
                className="w-full bg-transparent border border-white/20 text-white px-4 py-3 focus:outline-none focus:border-white transition-colors text-sm"
                placeholder="••••••••"
                minLength={6}
              />
            </div>

            <button
              type="submit"
              disabled={loading}
              className="w-full bg-white text-black font-medium py-4 uppercase tracking-widest text-sm hover:bg-white/90 transition-colors mt-4 disabled:opacity-50"
            >
              {loading ? "OLUŞTURULUYOR..." : "HESAP OLUŞTUR"}
            </button>
          </form>

          <div className="relative my-8">
            <div className="absolute inset-0 flex items-center">
              <div className="w-full border-t border-white/10"></div>
            </div>
            <div className="relative flex justify-center text-xs uppercase tracking-widest">
              <span className="bg-[#0D0D0D] px-4 text-white/50">VEYA</span>
            </div>
          </div>

          <button
            onClick={handleGoogleLogin}
            type="button"
            className="w-full bg-transparent border border-white text-white font-medium py-3 uppercase tracking-widest text-sm hover:bg-white/10 transition-colors flex items-center justify-center gap-3"
          >
            <svg viewBox="0 0 24 24" className="w-5 h-5 fill-current">
              <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" />
              <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" />
              <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" />
              <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" />
            </svg>
            Google İLE KAYIT OL
          </button>

          <div className="mt-8 text-center text-sm text-white/50">
            Zaten hesabınız var mı?{" "}
            <Link href={routes.login} className="text-white hover:underline transition-all">
              GİRİŞ YAP
            </Link>
          </div>
        </div>
      </div>
    </div>
  );
}

"use client"

import { useEffect, useState, useMemo } from "react"
import { useSearchParams, useParams, notFound } from "next/navigation"
import { ProductListingPage } from "@/components/storefront/ProductListingPage"
import { collection, onSnapshot, query, where, doc } from "firebase/firestore"
import { db } from "@/lib/firebase"

interface CategoryMeta {
  slug: string
  title: string
  subCategories?: { slug: string; title: string }[]
}

import { Suspense } from "react"

function DynamicCategoryContent() {
  const params = useParams()
  const categorySlug = params.kategori as string

  const [products, setProducts] = useState<any[]>([])
  const [links, setLinks] = useState<any[]>([])
  const [categoryMeta, setCategoryMeta] = useState<CategoryMeta | null>(null)
  const [loading, setLoading] = useState(true)
  const [notFoundState, setNotFoundState] = useState(false)
  const searchParams = useSearchParams()

  const activeSub = searchParams.get("sub")

  // Load category metadata from settings/categories
  useEffect(() => {
    const unsub = onSnapshot(
      doc(db, "settings", "categories"),
      (snapshot) => {
        if (!snapshot.exists()) {
          setNotFoundState(true)
          setLoading(false)
          return
        }

        const data = snapshot.data()
        const list = (data?.list as CategoryMeta[]) ?? []
        const found = list.find((c) => c.slug === categorySlug)

        if (!found) {
          setNotFoundState(true)
          setLoading(false)
          return
        }

        setCategoryMeta(found)

        // Build subcategory links
        const basePath = `/${categorySlug}`
        const subLinks = [
          { href: basePath, label: "Tümü" },
          ...(found.subCategories ?? []).map((sub) => ({
            href: `${basePath}?sub=${sub.slug}`,
            label: sub.title,
          })),
        ]
        setLinks(subLinks)
      },
      (error) => {
        console.error("Error fetching category meta:", error)
        setNotFoundState(true)
        setLoading(false)
      }
    )

    return () => unsub()
  }, [categorySlug])

  // Load products for this category
  useEffect(() => {
    const qProducts = query(
      collection(db, "products"),
      where("category", "==", categorySlug)
    )

    const unsub = onSnapshot(
      qProducts,
      (snapshot) => {
        const fetchedProducts: any[] = []
        snapshot.forEach((doc) => {
          fetchedProducts.push({ id: doc.id, ...doc.data() })
        })
        setProducts(fetchedProducts)
        setLoading(false)
      },
      (error) => {
        console.error("Error fetching products:", error)
        setLoading(false)
      }
    )

    return () => unsub()
  }, [categorySlug])

  // Filter by subcategory
  const filteredProducts = useMemo(() => {
    if (!activeSub) return products
    return products.filter((p) => p.subCategory === activeSub)
  }, [products, activeSub])

  const activeLink = activeSub
    ? `/${categorySlug}?sub=${activeSub}`
    : `/${categorySlug}`

  if (notFoundState) {
    notFound()
  }

  if (loading) {
    return (
      <div className="w-full min-h-screen bg-black flex items-center justify-center pt-20">
        <div className="w-10 h-10 border-2 border-white/20 border-t-white rounded-full animate-spin" />
      </div>
    )
  }

  return (
    <ProductListingPage
      title={categoryMeta?.title ?? categorySlug}
      description=""
      products={filteredProducts}
      links={links}
      activeLink={activeLink}
      emptyMessage={
        activeSub
          ? "Bu alt kategoride henüz ürün bulunmuyor."
          : "Yakında yeni ürünler eklenecektir."
      }
    />
  )
}

export default function DynamicCategoryPage() {
  return (
    <Suspense fallback={
      <div className="w-full min-h-screen bg-black flex items-center justify-center pt-20">
        <div className="w-10 h-10 border-2 border-white/20 border-t-white rounded-full animate-spin" />
      </div>
    }>
      <DynamicCategoryContent />
    </Suspense>
  )
}

"use client"

import { useEffect, useState, useMemo } from "react"
import { useSearchParams } from "next/navigation"
import { ProductListingPage } from "@/components/storefront/ProductListingPage"
import { collection, getDocs, getDoc, query, where, doc } from "firebase/firestore"
import { db } from "@/lib/firebase"

import { Suspense } from "react"

function AccessoriesContent() {
  const [products, setProducts] = useState<any[]>([])
  const [links, setLinks] = useState<any[]>([])
  const [loading, setLoading] = useState(true)
  const searchParams = useSearchParams()

  const activeSub = searchParams.get("sub")

  useEffect(() => {
    const fetchData = async () => {
      // Fetch Products
      try {
        const q = query(
          collection(db, "products"),
          where("category", "==", "aksesuar")
        )
        const snapshot = await getDocs(q)
        const fetchedProducts: any[] = []
        snapshot.forEach((doc) => {
          fetchedProducts.push({ id: doc.id, ...doc.data() })
        })
        setProducts(fetchedProducts)
      } catch (error) {
        console.error("Error fetching accessory products:", error)
      } finally {
        setLoading(false)
      }

      // Fetch Categories
      try {
        const catSnap = await getDoc(doc(db, "settings", "categories"))
        if (catSnap.exists()) {
          const data = catSnap.data()
          const list = (data?.list as Array<{ slug: string; title: string; subCategories?: Array<{ slug: string; title: string }> }>) ?? []
          const aksCat = list.find((c) => c.slug === "aksesuar")
          const subs = aksCat?.subCategories ?? []

          if (subs.length > 0) {
            setLinks([
              { href: "/aksesuar", label: "Tümü" },
              ...subs.map((sub) => ({
                href: `/aksesuar?sub=${sub.slug}`,
                label: sub.title,
              })),
            ])
          }
        }
      } catch (error) {
        console.error("Error fetching categories:", error)
      }
    }

    fetchData()
  }, [])

  const filteredProducts = useMemo(() => {
    if (!activeSub) return products
    return products.filter((p) => p.subCategory === activeSub)
  }, [products, activeSub])

  const activeLink = activeSub ? `/aksesuar?sub=${activeSub}` : "/aksesuar"

  if (loading) {
    return (
      <div className="w-full min-h-screen bg-black flex items-center justify-center pt-20">
        <div className="w-10 h-10 border-2 border-white/20 border-t-white rounded-full animate-spin" />
      </div>
    )
  }

  return (
    <ProductListingPage
      title="Aksesuar"
      description="Kemer, kravat ve tamamlayıcı detaylarla stilinizi güçlendirin."
      products={filteredProducts}
      links={links}
      activeLink={activeLink}
      emptyMessage={
        activeSub
          ? "Bu alt kategoride henüz ürün bulunmuyor."
          : "Yakında yeni kategoriler ve ürünler eklenecektir."
      }
    />
  )
}

export default function AccessoriesPage() {
  return (
    <Suspense fallback={
      <div className="w-full min-h-screen bg-black flex items-center justify-center pt-20">
        <div className="w-10 h-10 border-2 border-white/20 border-t-white rounded-full animate-spin" />
      </div>
    }>
      <AccessoriesContent />
    </Suspense>
  )
}

"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/components/providers/AuthProvider";
import { useCartStore } from "@/store/cartStore";
import { collection, query, getDocs, addDoc, serverTimestamp, doc, updateDoc, orderBy, increment } from "firebase/firestore";
import { db } from "@/lib/firebase";
import { MapPin, Plus, CreditCard, ShoppingBag, CheckCircle, ShieldCheck } from "lucide-react";
import Image from "next/image";
import { storeConfig } from "@/lib/storeConfig";
import { routes } from "@/lib/routes";
import { Button } from "@/components/ui/button";

function formatPrice(value: number): string {
  return value.toLocaleString("tr-TR", {
    style: "currency",
    currency: "TRY",
  });
}

export default function CheckoutPage() {
  const router = useRouter();
  const { user, profile } = useAuth();

  const items = useCartStore((state) => state.items);
  const clearCart = useCartStore((state) => state.clearCart);
  const total = items.reduce((sum, item) => sum + item.price * item.quantity, 0);

  const [addresses, setAddresses] = useState<any[]>([]);
  const [selectedAddressId, setSelectedAddressId] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);
  const [placingOrder, setPlacingOrder] = useState(false);
  const [isAddingAddress, setIsAddingAddress] = useState(false);

  // New Address Form Data
  const [formData, setFormData] = useState({
    title: "Ev", fullName: profile?.firstName + " " + profile?.lastName || "", phone: profile?.phone || "", city: "", district: "", fullAddress: ""
  });

  useEffect(() => {
    // If cart is empty, go back to cart
    if (items.length === 0 && !placingOrder) {
      router.push(routes.cart);
    }
  }, [items, router, placingOrder]);

  useEffect(() => {
    if (!user) return;
    fetchAddresses();
  }, [user]);

  const fetchAddresses = async () => {
    if (!user) return;
    try {
      const q = query(collection(db, "users", user.uid, "addresses"), orderBy("createdAt", "desc"));
      const snapshot = await getDocs(q);
      const fetched: any[] = [];
      snapshot.docs.forEach((d) => fetched.push({ id: d.id, ...d.data() }));

      fetched.sort((a, b) => (a.isDefault === b.isDefault ? 0 : a.isDefault ? -1 : 1));
      setAddresses(fetched);

      if (fetched.length > 0) {
        setSelectedAddressId(fetched[0].id);
      } else {
        setIsAddingAddress(true);
      }
    } catch (error) {
      console.error("Error fetching addresses:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleSaveAddress = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) return;
    try {
      const docRef = await addDoc(collection(db, "users", user.uid, "addresses"), {
        ...formData,
        isDefault: addresses.length === 0,
        createdAt: serverTimestamp()
      });
      await fetchAddresses();
      setIsAddingAddress(false);
      setSelectedAddressId(docRef.id);
    } catch (error) {
      console.error("Error saving address:", error);
    }
  };

  const handleCompleteOrder = async () => {
    if (!user || !selectedAddressId) return;

    setPlacingOrder(true);
    const selectedAddress = addresses.find(a => a.id === selectedAddressId);

    try {
      // 1. Create order document in Firestore (Simulated payment success via Shopier)
      const orderId = `HN-${Math.floor(10000 + Math.random() * 90000)}`;

      const orderData = {
        orderId,
        items,
        total,
        status: "Sipariş Alındı",
        address: selectedAddress,
        createdAt: serverTimestamp(),
      };

      await addDoc(collection(db, "users", user.uid, "orders"), orderData);

      // 2. Decrement Stock for each item
      for (const item of items) {
        try {
          const productRef = doc(db, "products", item.id);
          await updateDoc(productRef, {
            stockCount: increment(-item.quantity)
          });
        } catch (err) {
          console.error(`Error updating stock for product ${item.id}:`, err);
        }
      }

      // 3. Clear Cart
      clearCart();

      // 3. Redirect to success
      router.push(`${routes.checkout}/success?orderId=${orderId}`);

    } catch (error) {
       console.error("Error creating order:", error);
       setPlacingOrder(false);
    }
  };

  if (!user) {
    return (
      <div className="min-h-[60vh] flex flex-col items-center justify-center text-center p-4">
         <ShieldCheck className="w-16 h-16 text-white/30 mb-6" />
         <h1 className="text-2xl font-light text-white tracking-widest uppercase mb-4">GÜVENLİ ÖDEME</h1>
         <p className="text-white/60 mb-8 max-w-md">Siparişinize devam edebilmek için hesabınıza giriş yapmanız veya kayıt olmanız gerekmektedir.</p>
         <Button onClick={() => router.push(routes.login)} className="bg-white text-black hover:bg-white/90 uppercase tracking-widest px-10 h-14">
           GİRİŞ YAP VEYA KAYIT OL
         </Button>
      </div>
    );
  }

  if (loading) {
    return (
      <div className="flex justify-center items-center min-h-[60vh]">
        <div className="w-8 h-8 border-2 border-white/20 border-t-white rounded-full animate-spin" />
      </div>
    );
  }

  return (
    <div className="w-full min-h-screen bg-black pt-10 pb-24">
      <div className="container max-w-screen-xl mx-auto px-4 md:px-8">

        <h1 className="text-2xl sm:text-3xl font-light uppercase tracking-widest text-white mb-2">
          GÜVENLİ ÖDEME
        </h1>
        <p className="text-white/50 text-sm mb-10">Siparişinizi tamamlamak için adres ve ödeme bilgilerinizi giriniz.</p>

        <div className="grid grid-cols-1 lg:grid-cols-[minmax(0,1fr)_400px] gap-8">

          <div className="space-y-8">
            {/* ── ADDRESS SECTION ── */}
            <section className="bg-white/5 border border-white/10 p-6 sm:p-8">
              <div className="flex items-center gap-3 mb-6 pb-4 border-b border-white/10 text-white">
                <MapPin className="w-5 h-5 text-white/70" />
                <h2 className="text-lg uppercase tracking-widest font-medium">1. TESLİMAT ADRESİ</h2>
              </div>

              {isAddingAddress ? (
                <form onSubmit={handleSaveAddress} className="space-y-5 animate-in fade-in slide-in-from-top-4 duration-500">
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                    <div className="space-y-1.5">
                      <label className="text-xs uppercase tracking-widest text-white/50">Adres Başlığı</label>
                      <input required value={formData.title} onChange={e => setFormData({...formData, title: e.target.value})} className="w-full bg-black border border-white/20 px-4 py-3 text-white text-sm focus:outline-none focus:border-white transition-colors" placeholder="Ev, İş vb." />
                    </div>
                    <div className="space-y-1.5">
