"use client"

import { useEffect, useState, useMemo } from "react"
import { useSearchParams } from "next/navigation"
import { ProductListingPage } from "@/components/storefront/ProductListingPage"
import { routes } from "@/lib/routes"
import { collection, getDocs, getDoc, query, where, doc } from "firebase/firestore"
import { db } from "@/lib/firebase"

import { Suspense } from "react"

function ClothingContent() {
  const [products, setProducts] = useState<any[]>([])
  const [links, setLinks] = useState<any[]>([])
  const [loading, setLoading] = useState(true)
  const searchParams = useSearchParams()

  // Current subcategory slug from URL (?sub=tisort)
  const activeSub = searchParams.get("sub")

  useEffect(() => {
    const fetchData = async () => {
      // Fetch Products
      try {
        const qProducts = query(
          collection(db, "products"),
          where("category", "==", "giyim")
        )
        const snapshot = await getDocs(qProducts)
        const fetchedProducts: any[] = []
        snapshot.forEach((doc) => {
          fetchedProducts.push({ id: doc.id, ...doc.data() })
        })
        setProducts(fetchedProducts)
      } catch (error) {
        console.error("Error fetching clothing products:", error)
      } finally {
        setLoading(false)
      }

      // Fetch Categories
      try {
        const catSnap = await getDoc(doc(db, "settings", "categories"))
        if (catSnap.exists()) {
          const data = catSnap.data()
          const list = (data?.list as Array<{ slug: string; title: string; subCategories?: Array<{ slug: string; title: string }> }>) ?? []
          const giyimCat = list.find((c) => c.slug === "giyim")
          const subs = giyimCat?.subCategories ?? []

          const newLinks = [
            { href: routes.clothing, label: "Tümü" },
            ...subs.map((sub) => ({
              href: `${routes.clothing}?sub=${sub.slug}`,
              label: sub.title,
            })),
          ]
          setLinks(newLinks)
        } else {
          // Fallback: try subcategories collection
          const subSnap = await getDocs(collection(db, "subcategories"))
          const fetchedSub: any[] = []
          subSnap.forEach((doc) => {
            fetchedSub.push({ id: doc.id, ...doc.data() })
          })
          const newLinks = [
            { href: routes.clothing, label: "Tümü" },
            ...fetchedSub.map((sub) => ({
              href: `${routes.clothing}?sub=${sub.slug || sub.id}`,
              label: sub.title || sub.name || sub.id,
            })),
          ]
          setLinks(newLinks)
        }
      } catch (error) {
        console.error("Error fetching categories:", error)
      }
    }

    fetchData()
  }, [])

  // ── Filter products by subcategory when ?sub= is present ──
  const filteredProducts = useMemo(() => {
    if (!activeSub) return products
    return products.filter((p) => p.subCategory === activeSub)
  }, [products, activeSub])

  // Determine which link is currently active
  const activeLink = activeSub
    ? `${routes.clothing}?sub=${activeSub}`
    : routes.clothing

  if (loading) {
    return (
      <div className="w-full min-h-screen bg-black flex items-center justify-center pt-20">
        <div className="w-10 h-10 border-2 border-white/20 border-t-white rounded-full animate-spin" />
      </div>
    )
  }

  return (
    <ProductListingPage
      title="Giyim"
      description="Modern kesimler, premium kumaşlar ve günlük şıklık."
      products={filteredProducts}
      links={links}
      activeLink={activeLink}
      emptyMessage={
        activeSub
          ? "Bu alt kategoride henüz ürün bulunmuyor."
          : undefined
      }
    />
  )
}

export default function ClothingPage() {
  return (
    <Suspense fallback={
      <div className="w-full min-h-screen bg-black flex items-center justify-center pt-20">
        <div className="w-10 h-10 border-2 border-white/20 border-t-white rounded-full animate-spin" />
      </div>
    }>
      <ClothingContent />
    </Suspense>
  )
}

"use client"

import { useEffect, useState } from "react"
import { ProductListingPage } from "@/components/storefront/ProductListingPage"
import { routes } from "@/lib/routes"
import { collection, onSnapshot, query, where } from "firebase/firestore"
import { db } from "@/lib/firebase"

export default function TrendPage() {
  const [products, setProducts] = useState<any[]>([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    const q = query(
      collection(db, "products"),
      where("isTrending", "==", true)
    )

    const unsubscribe = onSnapshot(
      q,
      (snapshot) => {
        const fetchedProducts: any[] = []
        snapshot.forEach((doc) => {
          fetchedProducts.push({ id: doc.id, ...doc.data() })
        })

        // Sort by salesCount DESC
        fetchedProducts.sort((a, b) => (b.salesCount || 0) - (a.salesCount || 0))

        setProducts(fetchedProducts)
        setLoading(false)
      },
      (error) => {
        console.error("Error fetching trending products:", error)
        setLoading(false)
      }
    )

    return () => unsubscribe()
  }, [])

  if (loading) {
    return (
      <div className="w-full min-h-screen bg-black flex items-center justify-center pt-20">
        <div className="w-10 h-10 border-2 border-white/20 border-t-white rounded-full animate-spin" />
      </div>
    )
  }

  return (
    <ProductListingPage
      title="Trend Ürünler"
      description="En çok ilgi gören ve en çok satılan parçaları keşfedin."
      products={products}
      links={[
        { href: routes.trending, label: "Trend" },
        { href: routes.newArrivals, label: "Yeni Gelenler" },
        { href: routes.allProducts, label: "Tüm Ürünler" },
      ]}
    />
  )
}

