      <div className="container max-w-screen-2xl mx-auto px-4 md:px-8 grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        {products.map((product) => (
          <ProductCard
            key={product.id}
            id={product.id}
            title={product.title}
            imageUrl={product.imageUrl}
            colorCount={product.colorCount || (product.variants ? new Set(product.variants.map((v: any) => v.color)).size : 0)}
            stockCount={product.stockCount}
            originalPrice={product.originalPrice}
            discountPrice={product.discountPrice}
            cartPrice={product.cartPrice}
