"use client"

import { useEffect, useState } from "react"
import { ProductListingPage } from "@/components/storefront/ProductListingPage"
import { collection, getDocs, query, where, orderBy } from "firebase/firestore"
import { db } from "@/lib/firebase"

export default function NewArrivalsPage() {
  const [products, setProducts] = useState<any[]>([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    const fetchProducts = async () => {
      try {
        const q = query(
          collection(db, "products"),
          where("isNewArrival", "==", true)
        )
        const snapshot = await getDocs(q)
        const fetchedProducts: any[] = []
        snapshot.forEach((doc) => {
          fetchedProducts.push({ id: doc.id, ...doc.data() })
        })

        // Optionally sort by createdAt DESC client-side if we can't do it in the query easily
        fetchedProducts.sort((a, b) => (b.createdAt || 0) - (a.createdAt || 0))

        setProducts(fetchedProducts)
      } catch (error) {
        console.error("Error fetching new arrivals:", error)
      } finally {
        setLoading(false)
      }
    }

    fetchProducts()
  }, [])

  if (loading) {
    return (
      <div className="w-full min-h-screen bg-black flex items-center justify-center pt-20">
        <div className="w-10 h-10 border-2 border-white/20 border-t-white rounded-full animate-spin" />
      </div>
    )
  }

  return (
    <ProductListingPage
      title="Yeni Gelenler"
      description="Bu sezonun en yeni ürünleriyle gardırobunuzu yenileyin."
      products={products}
      links={[]}
    />
  )
}

import { NextResponse } from "next/server";
import { seedDatabase } from "@/lib/seedData";

export async function GET() {
  try {
    const result = await seedDatabase();
    if (result.success) {
      return NextResponse.json(result);
    } else {
      return NextResponse.json(result, { status: 500 });
    }
  } catch (error: any) {
    return NextResponse.json({ error: error.message || "Internal Server Error" }, { status: 500 });
  }
}

"use client";

import { useEffect, useState } from "react";
import { useAuth } from "@/components/providers/AuthProvider";
import { collection, query, getDocs, addDoc, deleteDoc, updateDoc, doc, serverTimestamp, orderBy } from "firebase/firestore";
import { db } from "@/lib/firebase";
import { Plus, Trash2, Edit2, MapPin } from "lucide-react";
import { Button } from "@/components/ui/button";

interface Address {
  id: string;
  title: string;
  fullName: string;
  phone: string;
  city: string;
  district: string;
  fullAddress: string;
  isDefault: boolean;
  createdAt?: any;
}

export default function AddressesPage() {
  const { user } = useAuth();
  const [addresses, setAddresses] = useState<Address[]>([]);
  const [loading, setLoading] = useState(true);

  // Form states
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    title: "", fullName: "", phone: "", city: "", district: "", fullAddress: "", isDefault: false
  });
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    if (!user) return;
    fetchAddresses();
  }, [user]);

  const fetchAddresses = async () => {
    if (!user) return;
    setLoading(true);
    try {
      const q = query(collection(db, "users", user.uid, "addresses"), orderBy("createdAt", "desc"));
      const snapshot = await getDocs(q);
      const fetched: Address[] = [];
      snapshot.docs.forEach((d) => fetched.push({ id: d.id, ...d.data() } as Address));

      // Sort so default is first
      fetched.sort((a, b) => (a.isDefault === b.isDefault ? 0 : a.isDefault ? -1 : 1));
      setAddresses(fetched);
    } catch (error) {
      console.error("Error fetching addresses:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleOpenForm = (address?: Address) => {
    if (address) {
      setEditingId(address.id);
      setFormData({
        title: address.title,
        fullName: address.fullName,
        phone: address.phone,
        city: address.city,
        district: address.district,
        fullAddress: address.fullAddress,
        isDefault: address.isDefault
      });
    } else {
      setEditingId(null);
      setFormData({
        title: "", fullName: "", phone: "", city: "", district: "", fullAddress: "", isDefault: addresses.length === 0
      });
    }
    setIsFormOpen(true);
  };

  const handleCloseForm = () => {
    setIsFormOpen(false);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) return;
    setSaving(true);

    try {
      const addressData = {
        ...formData,
      };

      // If this is set as default, we need to remove default from others
      if (addressData.isDefault) {
        for (const addr of addresses) {
          if (addr.id !== editingId && addr.isDefault) {
             await updateDoc(doc(db, "users", user.uid, "addresses", addr.id), { isDefault: false });
          }
        }
      }

      if (editingId) {
        await updateDoc(doc(db, "users", user.uid, "addresses", editingId), addressData);
      } else {
        await addDoc(collection(db, "users", user.uid, "addresses"), {
          ...addressData,
          createdAt: serverTimestamp()
        });
      }

      await fetchAddresses();
      handleCloseForm();
    } catch (error) {
      console.error("Error saving address:", error);
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (!user || !confirm("Bu adresi silmek istediğinize emin misiniz?")) return;
    try {
      await deleteDoc(doc(db, "users", user.uid, "addresses", id));
      await fetchAddresses();
    } catch (error) {
      console.error("Error deleting address:", error);
    }
  };

  if (loading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="w-8 h-8 border-2 border-white/20 border-t-white rounded-full animate-spin" />
      </div>
    );
  }

  if (isFormOpen) {
    return (
      <div className="bg-white/5 border border-white/10 p-6 rounded-lg text-white">
        <h2 className="text-xl font-medium tracking-widest uppercase mb-6 pb-4 border-b border-white/10">
          {editingId ? "ADRESİ DÜZENLE" : "YENİ ADRES EKLE"}
        </h2>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-2">
              <label className="text-xs uppercase tracking-widest text-white/60">Adres Başlığı (Ev, İş vb.)</label>
              <input 
                required 
                value={formData.title}
                onChange={(e) => setFormData({...formData, title: e.target.value})}
                className="w-full bg-black border border-white/20 rounded-md px-4 py-3 focus:outline-none focus:border-white transition-colors" 
              />
            </div>
            <div className="space-y-2">
              <label className="text-xs uppercase tracking-widest text-white/60">Ad Soyad</label>
              <input 
                required 
                value={formData.fullName}
                onChange={(e) => setFormData({...formData, fullName: e.target.value})}
                className="w-full bg-black border border-white/20 rounded-md px-4 py-3 focus:outline-none focus:border-white transition-colors" 
              />
            </div>
            <div className="space-y-2">
              <label className="text-xs uppercase tracking-widest text-white/60">Telefon</label>
              <input 
                required 
                value={formData.phone}
                onChange={(e) => setFormData({...formData, phone: e.target.value})}
                className="w-full bg-black border border-white/20 rounded-md px-4 py-3 focus:outline-none focus:border-white transition-colors" 
              />
            </div>
            <div className="space-y-2">
              <label className="text-xs uppercase tracking-widest text-white/60">İl</label>
              <input 
                required 
                value={formData.city}
                onChange={(e) => setFormData({...formData, city: e.target.value})}
                className="w-full bg-black border border-white/20 rounded-md px-4 py-3 focus:outline-none focus:border-white transition-colors" 
              />
            </div>
            <div className="space-y-2">
              <label className="text-xs uppercase tracking-widest text-white/60">İlçe</label>
              <input 
                required 
                value={formData.district}
                onChange={(e) => setFormData({...formData, district: e.target.value})}
                className="w-full bg-black border border-white/20 rounded-md px-4 py-3 focus:outline-none focus:border-white transition-colors" 
              />
            </div>
          </div>
          <div className="space-y-2">
            <label className="text-xs uppercase tracking-widest text-white/60">Açık Adres</label>
            <textarea 
              required 
              rows={3}
              value={formData.fullAddress}
              onChange={(e) => setFormData({...formData, fullAddress: e.target.value})}
              className="w-full bg-black border border-white/20 rounded-md px-4 py-3 focus:outline-none focus:border-white transition-colors resize-none" 
            />
          </div>

          <div className="flex items-center gap-2 pt-2">
             <input 
               type="checkbox" 
               id="isDefault"
               checked={formData.isDefault}
               onChange={(e) => setFormData({...formData, isDefault: e.target.checked})}
               className="w-4 h-4 bg-black border-white/20 rounded accent-white"
             />
             <label htmlFor="isDefault" className="text-sm text-white/80">Varsayılan adres olarak ayarla</label>
          </div>

          <div className="flex justify-end gap-3 pt-6 border-t border-white/10 mt-6">
            <Button type="button" variant="ghost" onClick={handleCloseForm} className="text-white hover:bg-white/10 uppercase tracking-widest text-xs">
              İPTAL
            </Button>
            <Button type="submit" disabled={saving} className="bg-white text-black hover:bg-white/90 uppercase tracking-widest text-xs px-8">
              {saving ? "KAYDEDİLİYOR..." : "KAYDET"}
            </Button>
          </div>
        </form>
      </div>
    );
  }

  return (
    <div>
      <div className="flex justify-between items-center mb-8">
        <h2 className="text-xl font-medium tracking-widest text-white uppercase">
          ADRESLERİM
        </h2>
        <Button onClick={() => handleOpenForm()} className="bg-white text-black hover:bg-white/90 uppercase tracking-widest text-xs">
          <Plus className="w-4 h-4 mr-2" /> YENİ ADRES
        </Button>
      </div>

      {addresses.length > 0 ? (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {addresses.map((address) => (
            <div key={address.id} className={`p-5 rounded-lg border flex flex-col relative transition-colors ${address.isDefault ? "bg-white/10 border-white/30" : "bg-white/5 border-white/10 hover:border-white/20"}`}>
               {address.isDefault && (
                 <span className="absolute top-4 right-4 text-[10px] uppercase tracking-widest bg-white text-black px-2 py-1 rounded-sm font-bold">
                   VARSAYILAN
                 </span>
               )}
               <div className="flex items-center gap-2 mb-3">
                 <MapPin className="w-4 h-4 text-white/60" />
                 <h3 className="text-lg font-medium text-white">{address.title}</h3>
               </div>
               <div className="space-y-1 text-sm text-white/70 mb-6 flex-1">
                 <p className="font-medium text-white">{address.fullName}</p>
                 <p>{address.fullAddress}</p>
                 <p>{address.district} / {address.city}</p>
                 <p className="pt-2">{address.phone}</p>
               </div>

               <div className="flex gap-2 pt-4 border-t border-white/10 mt-auto">
                 <button onClick={() => handleOpenForm(address)} className="flex-1 flex justify-center items-center gap-2 py-2 text-xs uppercase tracking-widest text-white hover:bg-white/10 rounded transition-colors">
                   <Edit2 className="w-3 h-3" /> DÜZENLE
                 </button>
                 <button onClick={() => handleDelete(address.id)} className="flex-1 flex justify-center items-center gap-2 py-2 text-xs uppercase tracking-widest text-red-400 hover:bg-red-500/10 rounded transition-colors">
                   <Trash2 className="w-3 h-3" /> SİL
                 </button>
               </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="bg-white/5 border border-white/10 p-12 flex flex-col items-center justify-center text-center rounded-lg h-[300px]">
          <MapPin className="w-12 h-12 text-white/20 mb-4" />
          <p className="text-white/60 font-light mb-6">Henüz kayıtlı bir adresiniz bulunmuyor.</p>
          <Button onClick={() => handleOpenForm()} variant="outline" className="text-black bg-white border-white hover:bg-white/90 uppercase tracking-widest text-xs h-12 px-8">
            İLK ADRESİNİ EKLE
          </Button>
        </div>
      )}
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { useFavoritesStore } from "@/store/favoritesStore";
import { ProductCard } from "@/components/product/ProductCard";
import { collection, query, where, getDocs, documentId, doc, getDoc } from "firebase/firestore";
import { routes } from "@/lib/routes";
import { db } from "@/lib/firebase";
import { CatalogProduct } from "@/lib/catalog";
import Link from "next/link";
import { HeartCrack } from "lucide-react";
import { Button } from "@/components/ui/button";

export default function FavoritesPage() {
  const { items } = useFavoritesStore();
  const [products, setProducts] = useState<CatalogProduct[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchFavoriteProducts = async () => {
      if (items.length === 0) {
        setProducts([]);
        setLoading(false);
        return;
      }

      setLoading(true);
      try {
        const fetchedProducts: CatalogProduct[] = [];

        // Firestore 'in' query has a limit of 30, so we chunk it just in case
        const chunkSize = 30;
        for (let i = 0; i < items.length; i += chunkSize) {
          const chunk = items.slice(i, i + chunkSize);
          const q = query(
            collection(db, "products"),
            where(documentId(), "in", chunk)
          );

          const snapshot = await getDocs(q);
          snapshot.docs.forEach(doc => {
            fetchedProducts.push({ id: doc.id, ...doc.data() } as CatalogProduct);
          });
        }

        setProducts(fetchedProducts);
      } catch (error) {
        console.error("Error fetching favorite products:", error);
      } finally {
        setLoading(false);
      }
    };

    fetchFavoriteProducts();
  }, [items]);

  if (loading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="w-8 h-8 border-2 border-white/20 border-t-white rounded-full animate-spin" />
      </div>
    );
  }

  return (
    <div>
      <h2 className="text-xl font-medium tracking-widest text-white uppercase mb-8">
        FAVORİLERİM
      </h2>

      {products.length > 0 ? (
        <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
          {products.map((product) => (
            <ProductCard
              key={product.id}
              id={product.id}
              title={product.title}
              imageUrl={product.images[0] || "/placeholder-image.jpg"}
              originalPrice={product.originalPrice}
              discountPrice={product.discountPrice}
              colorCount={product.colorCount}
              stockCount={product.stockCount}
              isFavorite={true}
            />
          ))}
        </div>
      ) : (
        <div className="bg-white/5 border border-white/10 p-12 flex flex-col items-center justify-center text-center rounded-lg h-[400px]">
          <HeartCrack className="w-12 h-12 text-white/20 mb-4" />
          <p className="text-white/60 mb-6 font-light">
            Henüz favorilere eklediğiniz bir ürün bulunmuyor.
          </p>
          <Link href={routes.allProducts}>
            <Button variant="outline" className="text-black bg-white border-white hover:bg-white/90 uppercase tracking-widest text-xs h-12 px-8">
              ALIŞVERİŞE BAŞLA
            </Button>
          </Link>
        </div>
      )}
    </div>
  );
}

"use client";

import { useAuth } from "@/components/providers/AuthProvider";
import { Package, ChevronRight, Clock } from "lucide-react";
import Image from "next/image";
import Link from "next/link";
import { routes } from "@/lib/routes";
import { storeConfig } from "@/lib/storeConfig";
import { Button } from "@/components/ui/button";
import { useEffect, useState } from "react";
import { collection, query, where, orderBy, onSnapshot } from "firebase/firestore";
import { db } from "@/lib/firebase";

interface OrderItem {
  id: string;
  title: string;
  imageUrl: string;
  price: number;
}

interface Order {
  id: string;
  createdAt: any;
  totalAmount: number;
  status: string;
  statusColor?: string;
  items: OrderItem[];
}

export default function OrdersPage() {
  const { user } = useAuth();
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!user) return;

    const q = query(
      collection(db, "orders"),
      where("userId", "==", user.uid),
      orderBy("createdAt", "desc")
    );

    const unsubscribe = onSnapshot(q, (snapshot) => {
      const fetchedOrders = snapshot.docs.map(doc => {
        const data = doc.data();
        return {
          id: doc.id,
          ...data,
          // Assign default status colors if not present
          statusColor: data.statusColor || (
            data.status === "Teslim Edildi" ? "text-green-500" :
            data.status === "Kargoya Verildi" ? "text-blue-500" :
            data.status === "Hazırlanıyor" ? "text-orange-500" :
            "text-white/50"
          )
        } as Order;
      });
      setOrders(fetchedOrders);
      setLoading(false);
    }, (error) => {
      console.error("Orders fetch error:", error);
      setLoading(false);
    });

    return () => unsubscribe();
  }, [user]);

  const formatDate = (timestamp: any) => {
    if (!timestamp) return "";
    const date = timestamp.toDate ? timestamp.toDate() : new Date(timestamp);
    return date.toLocaleDateString("tr-TR", {
      day: "numeric",
      month: "long",
      year: "numeric"
    });
  };

  if (loading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="w-8 h-8 border-2 border-white/20 border-t-white rounded-full animate-spin" />
      </div>
    );
  }

  return (
    <div>
      <h2 className="text-xl font-medium tracking-widest text-white uppercase mb-8">
        SİPARİŞLERİM
      </h2>

      {orders.length > 0 ? (
        <div className="space-y-6">
          {orders.map((order) => (
            <div key={order.id} className="bg-white/5 border border-white/10 rounded-lg overflow-hidden">
              {/* Order Header */}
              <div className="bg-white/5 px-5 py-4 flex flex-col sm:flex-row sm:items-center justify-between border-b border-white/10 gap-4">
                 <div className="flex flex-wrap gap-x-8 gap-y-2">
                    <div>
                      <p className="text-[10px] text-white/50 uppercase tracking-widest mb-1">Sipariş Tarihi</p>
                      <p className="text-sm font-medium text-white">{formatDate(order.createdAt)}</p>
                    </div>
                    <div>
                      <p className="text-[10px] text-white/50 uppercase tracking-widest mb-1">Sipariş Özeti</p>
                      <p className="text-sm font-medium text-white">{order.items?.length || 0} Ürün</p>
                    </div>
                    <div>
                      <p className="text-[10px] text-white/50 uppercase tracking-widest mb-1">Toplam Tutar</p>
                      <p className="text-sm font-bold text-white">{(order.totalAmount || 0).toLocaleString("tr-TR")} {storeConfig.currency.symbol}</p>
                    </div>
                 </div>
                 <div className="flex flex-col sm:items-end">
                    <p className="text-[10px] text-white/50 uppercase tracking-widest mb-1">Sipariş No</p>
                    <p className="text-sm font-medium text-white">{order.id}</p>
                 </div>
              </div>

              {/* Order Body */}
              <div className="p-5">
                 <div className="flex items-center justify-between mb-4">
                   <div className="flex items-center gap-2">
                     <Clock className={`w-4 h-4 ${order.statusColor}`} />
                     <span className={`text-sm font-medium ${order.statusColor}`}>{order.status}</span>
                   </div>
                   <button className="text-xs text-white/70 hover:text-white flex items-center transition-colors">
                     SİPARİŞ DETAYI <ChevronRight className="w-3 h-3 ml-1" />
                   </button>
                 </div>

                 {/* Order Items */}
                 <div className="flex gap-4 overflow-x-auto pb-4 custom-scrollbar">
                   {order.items?.map((item, idx) => (
                     <div key={idx} className="shrink-0 flex gap-4 w-[280px] bg-black/40 p-3 rounded border border-white/5">
                        <div className="relative w-16 h-20 bg-white/5 shrink-0 rounded overflow-hidden">
                           <Image src={item.imageUrl || "/placeholder-image.jpg"} alt={item.title} fill className="object-cover" />
                        </div>
                        <div className="flex flex-col justify-center">
                           <p className="text-sm font-medium text-white line-clamp-2">{item.title}</p>
                           <p className="text-xs text-white/60 mt-1">{(item.price || 0).toLocaleString("tr-TR")} {storeConfig.currency.symbol}</p>
                        </div>
                     </div>
                   ))}
                 </div>
              </div>

            </div>
          ))}
        </div>
      ) : (
        <div className="bg-white/5 border border-white/10 p-12 flex flex-col items-center justify-center text-center rounded-lg h-[400px]">
          <Package className="w-12 h-12 text-white/20 mb-4" />
          <p className="text-white/60 font-light mb-6">Henüz bir siparişiniz bulunmuyor.</p>
          <Link href={routes.allProducts}>
             <Button variant="outline" className="text-black bg-white border-white hover:bg-white/90 uppercase tracking-widest text-xs h-12 px-8">
               ALIŞVERİŞE BAŞLA
             </Button>
          </Link>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { useAuth } from "@/components/providers/AuthProvider";
import { doc, updateDoc } from "firebase/firestore";
import { updateProfile as updateFirebaseProfile } from "firebase/auth";
import { db, auth } from "@/lib/firebase";
import { toast } from "sonner";

export default function ProfilePage() {
  const { user, profile, refreshProfile } = useAuth();

  const [firstName, setFirstName] = useState("");
  const [lastName, setLastName] = useState("");
  const [phone, setPhone] = useState("");
  const [loading, setLoading] = useState(false);

  // Load existing data
  useEffect(() => {
    if (profile) {
      setFirstName(profile.firstName || "");
      setLastName(profile.lastName || "");
      setPhone(profile.phone || "");
    }
  }, [profile]);

  const handleUpdate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) return;

    setLoading(true);
    try {
      // 1. Update Firebase Auth Profile (DisplayName)
      await updateFirebaseProfile(user, {
        displayName: `${firstName} ${lastName}`.trim(),
      });

      // 2. Update Firestore User Document
      const userRef = doc(db, "users", user.uid);
      await updateDoc(userRef, {
        firstName,
        lastName,
        phone,
      });

      // 3. Refresh Context Profile
      await refreshProfile();

      toast.success("Profil bilgileriniz başarıyla güncellendi.");
    } catch (error) {
      console.error("Profile update error:", error);
      toast.error("Profil güncellenirken bir hata oluştu.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-white/5 border border-white/10 p-6 sm:p-10">
      <h2 className="text-lg font-light tracking-widest uppercase text-white mb-8">
        HESAP BİLGİLERİ
      </h2>

      <form onSubmit={handleUpdate} className="space-y-6">
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
          <div>
            <label className="block text-xs uppercase tracking-widest text-white/50 mb-2">
              AD
            </label>
            <input
              type="text"
              value={firstName}
              onChange={(e) => setFirstName(e.target.value)}
              required
              className="w-full bg-transparent border border-white/20 text-white px-4 py-3 focus:outline-none focus:border-white transition-colors text-sm"
            />
          </div>
          <div>
            <label className="block text-xs uppercase tracking-widest text-white/50 mb-2">
              SOYAD
            </label>
            <input
              type="text"
              value={lastName}
              onChange={(e) => setLastName(e.target.value)}
              required
              className="w-full bg-transparent border border-white/20 text-white px-4 py-3 focus:outline-none focus:border-white transition-colors text-sm"
            />
          </div>
        </div>

        <div>
          <label className="block text-xs uppercase tracking-widest text-white/50 mb-2">
            E-POSTA ADRESİ (Değiştirilemez)
          </label>
          <input
            type="email"
            value={user?.email || ""}
            disabled
            className="w-full bg-black/50 border border-white/10 text-white/50 px-4 py-3 cursor-not-allowed text-sm"
          />
        </div>

        <div>
          <label className="block text-xs uppercase tracking-widest text-white/50 mb-2">
            TELEFON NUMARASI
          </label>
          <input
            type="tel"
            value={phone}
            onChange={(e) => setPhone(e.target.value)}
            placeholder="+90 (___) ___ __ __"
            className="w-full bg-transparent border border-white/20 text-white px-4 py-3 focus:outline-none focus:border-white transition-colors text-sm"
          />
        </div>

        <button
          type="submit"
          disabled={loading}
          className="bg-white text-black font-medium px-8 py-3 uppercase tracking-widest text-[11px] hover:bg-white/90 transition-colors disabled:opacity-50 mt-4"
        >
          {loading ? "KAYDEDİLİYOR..." : "DEĞİŞİKLİKLERİ KAYDET"}
        </button>
      </form>
    </div>
  );
}

"use client"

import { useEffect, useState } from "react";
import { ProductCard } from "@/components/product/ProductCard"
import Link from "next/link"
import { routes, slugify } from "@/lib/routes"
import { collection, getDocs, query, where, limit } from "firebase/firestore";
import { db } from "@/lib/firebase";

export function TrendingProducts() {
  const [trendingProducts, setTrendingProducts] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchProducts = async () => {
      try {
        const q = query(
          collection(db, "products"), 
          where("isTrending", "==", true),
          limit(4)
        );
        const snapshot = await getDocs(q);
        const fetchedProducts: any[] = [];
        snapshot.forEach((doc) => {
          fetchedProducts.push({
            id: doc.id,
            ...doc.data(),
          });
        });
        setTrendingProducts(fetchedProducts);
      } catch (error) {
        console.error("Error fetching trending products:", error);
      } finally {
        setLoading(false);
      }
    };

    fetchProducts();
  }, []);

  if (loading) {
    return (
      <section className="py-20 w-full max-w-screen-2xl mx-auto px-4 md:px-8 border-t border-white/5">
        <div className="flex flex-col md:flex-row justify-between items-center md:items-end mb-10 gap-4">
          <h2 className="text-2xl md:text-3xl font-light uppercase tracking-widest text-white text-center md:text-left">
            Trend Ürünler
          </h2>
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
          {[1, 2, 3, 4].map((skeleton) => (
            <div key={skeleton} className="aspect-[3/4] w-full bg-white/5 animate-pulse" />
          ))}
        </div>
      </section>
    );
  }

  // إذا لم يتم استرجاع منتجات فلا نعرض القسم
  if (trendingProducts.length === 0) return null;

  return (
    <section className="py-20 w-full max-w-screen-2xl mx-auto px-4 md:px-8 border-t border-white/5">
      <div className="flex flex-col md:flex-row justify-between items-center md:items-end mb-10 gap-4">
        <h2 className="text-2xl md:text-3xl font-light uppercase tracking-widest text-white text-center md:text-left">
          Trend Ürünler
        </h2>
        <Link
          href={routes.trending}
          className="text-xs uppercase tracking-widest text-white/60 hover:text-white transition-colors border-b border-white/30 pb-0.5"
        >
          Tümünü Gör
        </Link>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        {trendingProducts.map((product) => (
          <ProductCard
            key={product.id}
            id={product.id}
            title={product.title}
            imageUrl={product.imageUrl}
            colorCount={product.colorCount}
            stockCount={product.stockCount}
            originalPrice={product.originalPrice}
            discountPrice={product.discountPrice}
            cartPrice={product.cartPrice}
            productHref={routes.trendProduct(product.slug || slugify(product.title || product.id))}
          />
        ))}
      </div>
    </section>
  )
}

"use client";

import Image from "next/image";
import Link from "next/link";
import { Heart, ShoppingBag } from "lucide-react";
import { memo, useState } from "react";
import { useCartStore } from "@/store/cartStore";
import { useFavoritesStore } from "@/store/favoritesStore";
import { storeConfig } from "@/lib/storeConfig";
import { routes } from "@/lib/routes";

/* ───────────────────────── Types ───────────────────────── */

interface ProductCardProps {
  /** Unique product identifier */
  id: string;
  /** Primary product image URL */
  imageUrl: string;
  /** Product title (clamped to 2 lines) */
  title: string;
  /** Number of available colors (shows color badge when > 0) */
  colorCount?: number;
  /** Number of items remaining in stock */
  stockCount?: number;
  /** Original price before discount (shown with line-through) */
  originalPrice: number;
  /** Discounted selling price */
  discountPrice: number;
  /** Special price when added to cart (shows red banner) */
  cartPrice?: number;
  /** Whether the product is favorited */
  isFavorite?: boolean;
  /**
   * Custom text for the dark banner.
   * - If provided → overrides the global default
   * - If `null` → explicitly hides the banner
   * - If `undefined` → falls back to `storeConfig.defaultBannerText`
   */
  customBannerText?: string | null;
  /** Custom href for the product detail page. Defaults to routes.product(id) */
  productHref?: string;
  /** Callback when favorite icon is toggled */
  onFavoriteToggle?: (id: string) => void;
  /** Callback when cart icon is clicked */
  onAddToCart?: (id: string) => void;
}

/* ───────────────────────── Helpers ───────────────────────── */

function formatPrice(price: number): string {
  return price.toLocaleString(storeConfig.currency.locale, {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  });
}

/* ───────────────────────── Component ───────────────────────── */

export const ProductCard = memo(function ProductCard({
  id,
  imageUrl,
  title,
  colorCount,
  stockCount,
  originalPrice,
  discountPrice,
  cartPrice,
  isFavorite: isFavoriteProp = false,
  customBannerText,
  productHref,
  onFavoriteToggle,
  onAddToCart,
}: ProductCardProps) {
  const toggleFavorite = useFavoritesStore((state) => state.toggleFavorite);
  const isFavoriteStore = useFavoritesStore((state) => state.isFavorite(id));

  // Prop override vs store state
  const favorite = isFavoriteProp || isFavoriteStore;

  const addItem = useCartStore((state) => state.addItem);

  /* ── Banner text logic ── */
  const resolveBannerText = (): string | null => {
    // Show 'Low Stock' warning if stock is between 1 and 5
    if (stockCount !== undefined && stockCount > 0 && stockCount <= 5) {
      return "TÜKENMEK ÜZERE";
    }
    // Prop explicitly provided (including null to hide)
    if (customBannerText !== undefined) return customBannerText;
    // Fall back to global config
    return storeConfig.defaultBannerText;
  };
  const bannerText = resolveBannerText();

  /* ── Handlers ── */
  const handleFavoriteClick = async (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    await toggleFavorite(id);
    onFavoriteToggle?.(id);
  };

  const handleCartClick = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    addItem({
      id,
      cartItemId: `${id}-Standart-Standart`,
      name: title,
      price: cartPrice && cartPrice > 0 ? cartPrice : discountPrice,
      quantity: 1,
      size: "Standart",
      color: "Standart",
      image: imageUrl,
    });
    onAddToCart?.(id);
  };

  /* ── Discount percentage ── */
  const discountPercent =
    originalPrice > discountPrice
      ? Math.round(((originalPrice - discountPrice) / originalPrice) * 100)
      : 0;

  return (
    <div className="group relative flex flex-col bg-white overflow-hidden transition-shadow duration-300 hover:shadow-xl rounded-sm">
      {/* ═══════════ IMAGE WRAPPER ═══════════ */}
      <div className="block relative w-full aspect-[3/4] overflow-hidden bg-neutral-100">
        {/* Product image link */}
        <Link href={productHref || routes.product(id)} className="absolute inset-0 z-0 block">
          <Image
            src={imageUrl}
            alt={title}
            fill
            className="object-cover transition-transform duration-700 group-hover:scale-105"
            sizes="(max-width: 640px) 100vw, (max-width: 1024px) 50vw, 25vw"
          />
        </Link>

        {/* ── Favorite icon (top-right) ── */}
        <button
          onClick={handleFavoriteClick}
          aria-label={favorite ? "Favorilerden çıkar" : "Favorilere ekle"}
          className="absolute top-3 right-3 z-20 w-9 h-9 flex items-center justify-center rounded-full bg-white/90 backdrop-blur-sm shadow-md hover:bg-white transition-colors duration-200 touch-manipulation"
        >
          <Heart
            className={`w-[18px] h-[18px] transition-colors duration-200 ${
              favorite
                ? "fill-red-500 text-red-500"
                : "fill-none text-neutral-500 hover:text-red-400"
            }`}
          />
        </button>

        {/* ── Discount badge (top-left) ── */}
        {discountPercent > 0 && (
          <span className="absolute top-3 left-3 z-20 bg-red-600 text-white text-[10px] font-bold px-2 py-1 rounded-sm tracking-wide pointer-events-none">
            %{discountPercent}
          </span>
        )}

        {/* ── Bottom overlay area (color badge + cart icon) ── */}
        <div className="absolute inset-x-0 bottom-0 z-10 flex items-end justify-between px-3 pointer-events-none" style={{ paddingBottom: bannerText ? "40px" : "12px" }}>
          {/* Color badge (bottom-left) */}
          {colorCount && colorCount > 0 ? (
            <div className="flex items-center gap-1.5 bg-white/95 backdrop-blur-sm rounded-full px-2.5 py-1 shadow-md mb-1 pointer-events-auto">
              {/* Multi-color gradient circle */}
              <span
                className="w-4 h-4 rounded-full shrink-0"
                style={{
                  background:
                    "conic-gradient(#e74c3c, #f39c12, #2ecc71, #3498db, #9b59b6, #e74c3c)",
                }}
              />
              <span className="text-[11px] font-medium text-neutral-700 whitespace-nowrap">
                {colorCount} Renk
              </span>
            </div>
          ) : (
            <div /> /* Spacer to keep cart icon right-aligned */
          )}

          {/* Cart icon (bottom-right) */}
          <button
            onClick={handleCartClick}
            aria-label="Sepete ekle"
            className="w-9 h-9 flex items-center justify-center rounded-full bg-white/95 backdrop-blur-sm shadow-md hover:bg-white transition-colors duration-200 mb-1 pointer-events-auto touch-manipulation"
          >
            <ShoppingBag className="w-[18px] h-[18px] text-neutral-700" />
          </button>
        </div>

        {/* ── Banner (bottom edge of image) ── */}
        {bannerText && (
          <div 
            className={`absolute inset-x-0 bottom-0 z-10 py-2 pointer-events-none ${
              bannerText === "TÜKENMEK ÜZERE" 
                ? "bg-gradient-to-r from-neutral-300 via-neutral-100 to-neutral-300 shadow-[0_-2px_10px_rgba(0,0,0,0.1)]" 
                : "bg-[#1a1a2e]"
            }`}
          >
            <p className={`text-center text-[11px] font-bold tracking-[0.15em] uppercase ${
              bannerText === "TÜKENMEK ÜZERE" ? "text-neutral-900" : "text-white"
            }`}>
              {bannerText}
            </p>
          </div>
        )}
      </div>

      {/* ═══════════ PRODUCT DETAILS ═══════════ */}
      <div className="flex flex-col items-center px-3 pt-3 pb-2 space-y-1.5">
        {/* Title */}
        <Link
          href={productHref || routes.product(id)}
          className="text-sm font-bold text-neutral-800 text-center leading-tight line-clamp-2 hover:text-neutral-600 transition-colors"
        >
          {title}
        </Link>

        {/* Pricing row */}
        <div className="flex items-center justify-center gap-2.5">
          {originalPrice > discountPrice && (
            <span className="text-sm text-neutral-400 line-through">
              {formatPrice(originalPrice)} {storeConfig.currency.symbol}
            </span>
          )}
          <span className="text-base font-bold text-[#8b1a1a]">
            {formatPrice(discountPrice)} {storeConfig.currency.symbol}
          </span>
        </div>
      </div>

      {/* ── Cart price banner (red) ── */}
      <div className="w-full bg-[#8b0000] py-2 mt-auto">
        <p className="text-center text-[11px] font-semibold text-white tracking-wide">
          Sepetteki Fiyatı{" "}
          <span className="font-bold text-xs">
            {formatPrice(cartPrice && cartPrice > 0 ? cartPrice : discountPrice)} {storeConfig.currency.symbol}
          </span>
        </p>
      </div>
    </div>
  );
});

"use client";

import { Accordion, AccordionContent, AccordionItem, AccordionTrigger } from "@/components/ui/accordion";
import { Slider } from "@/components/ui/slider";
import { memo, useState, useEffect } from "react";
import { useSearchParams, useRouter, usePathname } from "next/navigation";
import type { FilterOption } from "@/lib/catalog";
import { cn } from "@/lib/utils";

interface ProductFiltersProps {
  /** Dynamic filters computed from actual products */
  dynamicFilters?: FilterOption[];
}

/** Default filters that always show regardless of subcategory if empty defaults are needed */
const defaultSizes = ["S", "M", "L", "XL"];
const defaultColors = [
  { name: "Siyah", hex: "#000000" },
  { name: "Beyaz", hex: "#FFFFFF" },
  { name: "Lacivert", hex: "#0A192F" },
  { name: "Gri", hex: "#808080" },
  { name: "Bej", hex: "#F5F5DC" },
];

export const ProductFilters = memo(function ProductFilters({ dynamicFilters = [] }: ProductFiltersProps) {
  const router = useRouter();
  const pathname = usePathname();
  const searchParams = useSearchParams();

  // Local price range state for slider to avoid stuttering during slide
  const [priceRange, setPriceRange] = useState([0, 10000]);

  // Read URL active states
  const activeSizes = searchParams.getAll("size");
  const activeColors = searchParams.getAll("color");

  const isSelected = (filterId: string, value: string) => {
    if (filterId === "size" || filterId === "beden") {
      return activeSizes.includes(value);
    }
    if (filterId === "color" || filterId === "renk") {
      return activeColors.includes(value);
    }
    return searchParams.getAll(filterId).includes(value);
  };

  const toggleFilter = (filterId: string, value: string) => {
    const params = new URLSearchParams(searchParams.toString());
    const currentValues = params.getAll(filterId);

    if (currentValues.includes(value)) {
      // Remove it
      params.delete(filterId);
      currentValues.filter(v => v !== value).forEach(v => params.append(filterId, v));
    } else {
      // Add it
      params.append(filterId, value);
    }

    router.push(`${pathname}?${params.toString()}`, { scroll: false });
  };

  const clearAllFilters = () => {
    const params = new URLSearchParams(searchParams.toString());
    params.delete("size");
    params.delete("color");
    params.delete("beden");
    params.delete("renk");
    params.delete("fabricType");
    params.delete("fit");
    params.delete("tip");
    params.delete("collarType");
    // Preserve 'sort' and 'sub' if they exist
    router.push(`${pathname}?${params.toString()}`, { scroll: false });
  };

  const activeFiltersCount = activeSizes.length + activeColors.length
    + searchParams.getAll("fabricType").length
    + searchParams.getAll("fit").length
    + searchParams.getAll("tip").length
    + searchParams.getAll("collarType").length;

  const hasDynamicFilters = dynamicFilters.length > 0;

  return (
    <div className="w-full space-y-6">
      <div>
        <h3 className="text-lg font-light tracking-widest uppercase mb-4 text-white">
          Filtrele
        </h3>
        <div className="h-[1px] w-full bg-white/10 mb-4" />
      </div>

      <Accordion className="w-full text-white/80" defaultValue={["size", "color", "price"]}>

        {hasDynamicFilters ? (
          <>
            {dynamicFilters.map((filter) => (
              <AccordionItem key={filter.id} value={filter.id} className="border-b border-white/10">
                <AccordionTrigger className="hover:no-underline hover:text-white uppercase text-sm tracking-wider font-medium">
                  {filter.label}
                </AccordionTrigger>
                <AccordionContent>
                  {filter.id === "color" || filter.id === "renk" ? (
                    /* Color filter — show colored dots */
                    <div className="flex flex-col space-y-3 pt-2">
                      {filter.values.map((value) => {
                        const colorHex = getColorHex(value);
                        return (
                          <button
                            key={value}
                            type="button"
                            onClick={() => toggleFilter(filter.id, value)}
                            className="flex items-center space-x-3 cursor-pointer group"
                          >
                            <div className={cn(
                              "relative flex items-center justify-center w-5 h-5 rounded-full border transition-colors",
                              isSelected(filter.id, value) ? "border-white ring-1 ring-white" : "border-white/20 group-hover:border-white"
                            )}>
                              <span className="block w-3 h-3 rounded-full" style={{ backgroundColor: colorHex }} />
                            </div>
                            <span className={cn(
                              "text-sm font-light transition-colors",
                              isSelected(filter.id, value) ? "text-white" : "text-white/70 group-hover:text-white"
                            )}>
                              {value}
                            </span>
                          </button>
                        );
                      })}
                    </div>
                  ) : filter.id === "size" || filter.id === "beden" ? (
                    /* Size filter — grid of buttons */
                    <div className="grid grid-cols-4 gap-2 pt-2">
                      {filter.values.map((value) => (
                        <button
                          key={value}
                          type="button"
                          onClick={() => toggleFilter(filter.id, value)}
                          className={cn(
                            "h-10 border flex items-center justify-center text-xs transition-colors cursor-pointer",
                            isSelected(filter.id, value)
                              ? "bg-white text-black border-white"
                              : "border-white/20 hover:bg-white hover:text-black"
                          )}
                        >
                          {value}
                        </button>
                      ))}
                    </div>
                  ) : (
                    /* Generic filter — text list */
                    <div className="flex flex-col space-y-2 pt-2">
                      {filter.values.map((value) => (
                        <button
                          key={value}
                          type="button"
                          onClick={() => toggleFilter(filter.id, value)}
                          className={cn(
                            "flex items-center space-x-3 cursor-pointer group text-left",
                          )}
                        >
                          <div className={cn(
                            "w-4 h-4 rounded-sm border flex items-center justify-center transition-colors",
                            isSelected(filter.id, value)
                              ? "bg-white border-white"
                              : "border-white/30 group-hover:border-white/60"
                          )}>
                            {isSelected(filter.id, value) && (
                              <svg className="w-3 h-3 text-black" viewBox="0 0 12 12" fill="none">
                                <path d="M2 6L5 9L10 3" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
                              </svg>
                            )}
                          </div>
                          <span className={cn(
                            "text-sm font-light transition-colors",
                            isSelected(filter.id, value) ? "text-white" : "text-white/70 group-hover:text-white"
                          )}>
                            {value}
                          </span>
                        </button>
                      ))}
                    </div>
                  )}
                </AccordionContent>
              </AccordionItem>
            ))}
          </>
        ) : (
          <>
            {/* Size Filter */}
            <AccordionItem value="size" className="border-b border-white/10">
              <AccordionTrigger className="hover:no-underline hover:text-white uppercase text-sm tracking-wider font-medium">
                Beden
              </AccordionTrigger>
              <AccordionContent>
                <div className="grid grid-cols-4 gap-2 pt-2">
                  {defaultSizes.map((size) => (
                    <button
                      key={size}
                      type="button"
                      onClick={() => toggleFilter("size", size)}
                      className={cn(
                        "h-10 border flex items-center justify-center text-xs transition-colors cursor-pointer",
                        isSelected("size", size)
                          ? "bg-white text-black border-white"
                          : "border-white/20 hover:bg-white hover:text-black"
                      )}
                    >
                      {size}
                    </button>
                  ))}
                </div>
              </AccordionContent>
            </AccordionItem>

            {/* Color Filter */}
            <AccordionItem value="color" className="border-b border-white/10">
              <AccordionTrigger className="hover:no-underline hover:text-white uppercase text-sm tracking-wider font-medium">
                Renk
              </AccordionTrigger>
              <AccordionContent>
                <div className="flex flex-col space-y-3 pt-2">
                  {defaultColors.map((color) => (
                    <button
                      key={color.name}
                      type="button"
                      onClick={() => toggleFilter("color", color.name)}
                      className="flex items-center space-x-3 cursor-pointer group"
                    >
                      <div className={cn(
                        "relative flex items-center justify-center w-5 h-5 rounded-full border transition-colors",
                        isSelected("color", color.name) ? "border-white ring-1 ring-white" : "border-white/20 group-hover:border-white"
                      )}>
                        <span className="block w-3 h-3 rounded-full" style={{ backgroundColor: color.hex }} />
                      </div>
                      <span className={cn(
                        "text-sm font-light transition-colors",
                        isSelected("color", color.name) ? "text-white" : "text-white/70 group-hover:text-white"
                      )}>
                        {color.name}
                      </span>
                    </button>
                  ))}
                </div>
              </AccordionContent>
            </AccordionItem>
          </>
        )}

        {/* Price Filter — always shown */}
        <AccordionItem value="price" className="border-b border-white/10">
          <AccordionTrigger className="hover:no-underline hover:text-white uppercase text-sm tracking-wider font-medium">
            Fiyat
          </AccordionTrigger>
          <AccordionContent>
            <div className="pt-6 pb-2 space-y-4">
              <Slider 
                defaultValue={[0, 10000]} 
                max={15000} 
                step={100}
                value={priceRange}
                onValueChange={(val) => Array.isArray(val) && setPriceRange(val as number[])}
                className="w-full"
              />
              <div className="flex justify-between items-center text-xs font-light text-white/50">
                <span>{priceRange[0]} TL</span>
                <span>{priceRange[1]}+ TL</span>
              </div>
            </div>
          </AccordionContent>
        </AccordionItem>

      </Accordion>

      {/* Active filter count & Clear */}
      {activeFiltersCount > 0 && (
        <button
          type="button"
          onClick={clearAllFilters}
          className="w-full py-3 mt-4 text-[10px] sm:text-xs uppercase tracking-widest text-white/80 border border-white/20 hover:bg-white/5 hover:text-white transition-colors cursor-pointer"
        >
          Filtreleri Temizle ({activeFiltersCount})
        </button>
      )}
    </div>
  );
});

/** Helper — maps Turkish color names to hex values */
function getColorHex(colorName: string): string {
  const map: Record<string, string> = {
    "Siyah": "#000000",
    "Beyaz": "#FFFFFF",
    "Gri": "#808080",
    "Lacivert": "#0A192F",
    "Bej": "#F5F5DC",
    "Haki": "#5F6B4A",
    "Bordo": "#800020",
    "Kırmızı": "#E74C3C",
    "Mavi": "#3498DB",
  };
  return map[colorName] ?? "#808080";
}

"use client";

import { useState, useMemo } from "react";
import { Button } from "@/components/ui/button";
